func uploadFile(w http.ResponseWriter, r *http.Request) {
	if r.Method != "POST" {
		http.Error(w, "Invalid request method", http.StatusBadRequest)
		return
	}

	var buf [16 << 20]io.Reader // 16MB buffer

	if r.Header.Get("Content-Type") == "" || !strings.Contains(r.Header.Get("Content-Type"), "multipart/form-data") {
		http.Error(w, "Invalid content type", http.StatusBadRequest)
		return
	}

	if err := r.ParseMultipartForm(32 << 20); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	for _, fileHeader := range r.MultipartForm.File["file"] {
		if err := fileHeader.Open(); err != nil {
			log.Printf("Error opening file: %v", err)
			continue
		}
		defer fileHeader.Close()

		f, err := ratelimit.NewFileWriter(16 << 20) // 16MB buffer
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}

		if _, err := io.Copy(f, fileHeader); err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}

		f.Close()

		filePath := fmt.Sprintf("public/%s", fileHeader.Filename)

		if err := f.SaveTo(filePath); err != nil {
			log.Printf("Error saving file: %v", err)
			continue
		}
		w.Write([]byte(filePath))
		return
	}

	http.Error(w, "No file provided in the request", http.StatusBadRequest)
}

